"use strict";(self.webpackChunkdst_api_webdocs=self.webpackChunkdst_api_webdocs||[]).push([[63905],{577239:e=>{e.exports=JSON.parse('{"tag":{"label":"movement","permalink":"/dst-api-webdocs/docs/tags/movement","allTagsPath":"/dst-api-webdocs/docs/tags","count":43,"items":[{"id":"game-scripts/components/aoeweapon_lunge","title":"Aoeweapon Lunge","description":"Implements a forward-lunge area-of-effect weapon mechanic that calculates directional hit and toss zones, then triggers OnHit/OnToss callbacks with physics-aware overlap checks.","permalink":"/dst-api-webdocs/docs/game-scripts/components/aoeweapon_lunge"},{"id":"game-scripts/behaviours/beargeroffscreen","title":"Beargeroffscreen","description":"Controls off-screen roaming behavior for Bearger by moving it along a predefined wandering path and destroying objects in its path.","permalink":"/dst-api-webdocs/docs/game-scripts/behaviours/beargeroffscreen"},{"id":"game-scripts/components/boatdrifter","title":"Boatdrifter","description":"Manages the physics and movement state of a boat entity, including drift detection, physics activation/deactivation, and wake test lifecycle.","permalink":"/dst-api-webdocs/docs/game-scripts/components/boatdrifter"},{"id":"game-scripts/components/boatring","title":"Boatring","description":"Manages rotation behavior and bumper collision detection for a boat entity in the game world.","permalink":"/dst-api-webdocs/docs/game-scripts/components/boatring"},{"id":"game-scripts/brains/centipedebrain","title":"Centipedebrain","description":"Implements AI behavior for centipede enemies, managing combat tracking, charging, face-targeting, and autonomous movement.","permalink":"/dst-api-webdocs/docs/game-scripts/brains/centipedebrain"},{"id":"game-scripts/stategraphs/commonstates","title":"Commonstates","description":"Provides reusable state definitions and event handlers for common entity behaviors such as movement, sleep, freezing, electrocution, death, and hopping.","permalink":"/dst-api-webdocs/docs/game-scripts/stategraphs/commonstates"},{"id":"game-scripts/brains/corpse_gestalt_brain","title":"Corpse Gestalt Brain","description":"Controls movement and behavior of a corpse-infesting entity in relation to its tracked corpse target and nearby players.","permalink":"/dst-api-webdocs/docs/game-scripts/brains/corpse_gestalt_brain"},{"id":"game-scripts/brains/deergemmedbrain","title":"Deergemmedbrain","description":"AI brain controlling deer gemmed behavior, managing responses to keeper status, combat, panic, and positioning relative to the keeper.","permalink":"/dst-api-webdocs/docs/game-scripts/brains/deergemmedbrain"},{"id":"game-scripts/components/embarker","title":"Embarker","description":"Manages the movement and positioning of an entity during embarkation or disembarkation onto/from a platform or designated position.","permalink":"/dst-api-webdocs/docs/game-scripts/components/embarker"},{"id":"game-scripts/cameras/followcamera","title":"Followcamera","description":"Manages camera positioning, movement, and update logic for following a target entity in the game world.","permalink":"/dst-api-webdocs/docs/game-scripts/cameras/followcamera"},{"id":"game-scripts/components/formationleader","title":"Formationleader","description":"Manages a group of followers arranged in a dynamic formation around a target entity, handling formation membership, positioning, and disbanding.","permalink":"/dst-api-webdocs/docs/game-scripts/components/formationleader"},{"id":"game-scripts/components/grogginess","title":"Grogginess","description":"Manages temporary impairment effects including grogginess, knockouts, and associated speed penalties on an entity.","permalink":"/dst-api-webdocs/docs/game-scripts/components/grogginess"},{"id":"game-scripts/components/herd","title":"Herd","description":"Manages a group of herd members (e.g., beefalo) around a central entity, handling membership, gathering, merging, position updates, and persistence.","permalink":"/dst-api-webdocs/docs/game-scripts/components/herd"},{"id":"game-scripts/brains/lightcrabbrain","title":"Lightcrabbrain","description":"Controls the AI behavior of a light-crab entity by managing state execution through a behavior tree, including fleeing from threats, seeking bait, wandering, and returning home.","permalink":"/dst-api-webdocs/docs/game-scripts/brains/lightcrabbrain"},{"id":"game-scripts/prefabs/lighterfire_haunteddoll","title":"Lighterfire Haunteddoll","description":"Creates and manages a haunted-doll-specific particle fire effect with dynamic smoke emission based on movement.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/lighterfire_haunteddoll"},{"id":"game-scripts/components/locomotor","title":"Locomotor","description":"Manages entity movement, pathfinding, and speed calculations, including walking, running, platform hopping, and speed modifier interactions.","permalink":"/dst-api-webdocs/docs/game-scripts/components/locomotor"},{"id":"game-scripts/brains/mandrakebrain","title":"Mandrakebrain","description":"Defines the behavior tree for a mandrake entity, managing its panic responses, following behavior, and movement patterns.","permalink":"/dst-api-webdocs/docs/game-scripts/brains/mandrakebrain"},{"id":"game-scripts/components/miasmawatcher","title":"MiasmaWatcher","description":"Tracks whether an entity is inside a miasma cloud and applies movement speed penalties accordingly.","permalink":"/dst-api-webdocs/docs/game-scripts/components/miasmawatcher"},{"id":"game-scripts/brains/molebrain","title":"Molebrain","description":"Controls AI behavior for mole entities, handling movement, home creation, bait stealing, and environmental avoidance.","permalink":"/dst-api-webdocs/docs/game-scripts/brains/molebrain"},{"id":"game-scripts/brains/moonbutterflybrain","title":"Moonbutterflybrain","description":"Controls the AI behavior of the Moon Butterfly, prioritizing escape from threats, homing to a remembered location, and wandering within a limited radius.","permalink":"/dst-api-webdocs/docs/game-scripts/brains/moonbutterflybrain"},{"id":"game-scripts/brains/moonstormstaticbrain","title":"Moonstormstaticbrain","description":"Assigns a wandering behavior to an entity that restricts movement to land tiles within active moonstorm zones.","permalink":"/dst-api-webdocs/docs/game-scripts/brains/moonstormstaticbrain"},{"id":"game-scripts/components/nonslipgrituser","title":"Nonslipgrituser","description":"Manages nonslip grit sources (e.g., items) on an entity and propagates delta updates to them.","permalink":"/dst-api-webdocs/docs/game-scripts/components/nonslipgrituser"},{"id":"game-scripts/components/oceanfishable","title":"Oceanfishable","description":"Manages the fishable state and behavior of ocean creatures when interacting with fishing rods, including stamina-based struggle mechanics and movement speed adjustments based on line tension.","permalink":"/dst-api-webdocs/docs/game-scripts/components/oceanfishable"},{"id":"game-scripts/brains/oceanshadowcreaturebrain","title":"Oceanshadowcreaturebrain","description":"Controls the AI behavior of ocean-based shadow creatures, including target management, harassment actions, and conditional teleportation to land.","permalink":"/dst-api-webdocs/docs/game-scripts/brains/oceanshadowcreaturebrain"},{"id":"game-scripts/brains/powdermonkeybrain","title":"Powdermonkeybrain","description":"AI brain controlling powder monkey characters, managing movement, looting, combat, and boat operations such as rowing, tinking, and cannon firing.","permalink":"/dst-api-webdocs/docs/game-scripts/brains/powdermonkeybrain"},{"id":"game-scripts/brains/rabbitking_bunnymanbrain","title":"Rabbitking Bunnymanbrain","description":"Provides AI behavior for rabbit-related minions under the Rabbit King\'s command, implementing movement, aggression, fleeing, and burrowing logic via a behavior tree.","permalink":"/dst-api-webdocs/docs/game-scripts/brains/rabbitking_bunnymanbrain"},{"id":"game-scripts/components/rooted","title":"Rooted","description":"Prevents an entity from moving by stopping physics and applying a speed multiplier of 0 via the locomotor component, while managing lifecycle via sources.","permalink":"/dst-api-webdocs/docs/game-scripts/components/rooted"},{"id":"game-scripts/components/sandstormwatcher","title":"Sandstormwatcher","description":"Manages movement speed penalties during sandstorms based on vision state, mounting, and storm intensity.","permalink":"/dst-api-webdocs/docs/game-scripts/components/sandstormwatcher"},{"id":"game-scripts/stategraphs/SGfused_shadeling_bomb","title":"Sgfused Shadeling Bomb","description":"Defines the state graph for the fused shadeling bomb entity, controlling its movement (walking), idle, spawn, and bounce behaviors.","permalink":"/dst-api-webdocs/docs/game-scripts/stategraphs/SGfused_shadeling_bomb"},{"id":"game-scripts/stategraphs/SGgrassgator","title":"Sggrassgator","description":"Manages the state machine for the Grass Gator entity, handling transitions between idle, attack, fall, dive, and death behaviors based on timers, events, and component states.","permalink":"/dst-api-webdocs/docs/game-scripts/stategraphs/SGgrassgator"},{"id":"game-scripts/stategraphs/SGmoose","title":"Sgmoose","description":"Stategraph for the Moose/Moosegoose entity that manages movement, Idle, combat (including disarm), egg-laying, flying, and death animations via state transitions and event handling.","permalink":"/dst-api-webdocs/docs/game-scripts/stategraphs/SGmoose"},{"id":"game-scripts/brains/shadow_knightbrain","title":"Shadow Knightbrain","description":"Controls the AI behavior of the Shadow Knight entity, coordinating combat actions, movement, and despawning logic via a behavior tree.","permalink":"/dst-api-webdocs/docs/game-scripts/brains/shadow_knightbrain"},{"id":"game-scripts/brains/shadowthrall_parasite_brain","title":"Shadowthrall Parasite Brain","description":"Controls the movement and lifecycle behavior of a shadow thrall parasite entity by removing it when no players are nearby and fleeing from players and shadow rift portals.","permalink":"/dst-api-webdocs/docs/game-scripts/brains/shadowthrall_parasite_brain"},{"id":"game-scripts/brains/sharkboi_waterbrain","title":"Sharkboi Waterbrain","description":"Defines the behavior tree for the Sharkboi entity when submerged in water, primarily using a simple wander task.","permalink":"/dst-api-webdocs/docs/game-scripts/brains/sharkboi_waterbrain"},{"id":"game-scripts/brains/sharkbrain","title":"Sharkbrain","description":"Manages the AI decision-making logic for sharks, controlling movement, aggression, feeding, and boat-following behavior in Don\'t Starve Together.","permalink":"/dst-api-webdocs/docs/game-scripts/brains/sharkbrain"},{"id":"game-scripts/brains/spatbrain","title":"Spatbrain","description":"Controls the behavioral logic for the Spat creature, managing combat prioritization, movement, weapon switching, and threat response via a behavior tree.","permalink":"/dst-api-webdocs/docs/game-scripts/brains/spatbrain"},{"id":"game-scripts/brains/sporebrain","title":"Sporebrain","description":"Manages AI behavior for spore-based entities by prioritizing follow or wander actions using a behavior tree.","permalink":"/dst-api-webdocs/docs/game-scripts/brains/sporebrain"},{"id":"game-scripts/brains/stageusherbrain","title":"Stageusherbrain","description":"Manages the behavior tree logic for the Stage Usher boss entity, coordinating movement, combat engagement, and return-to-spawn behavior.","permalink":"/dst-api-webdocs/docs/game-scripts/brains/stageusherbrain"},{"id":"game-scripts/brains/tornadobrain","title":"Tornadobrain","description":"Implements decision-making logic for a tornado entity, directing it to move toward or wander near a target location.","permalink":"/dst-api-webdocs/docs/game-scripts/brains/tornadobrain"},{"id":"game-scripts/brains/wanderingtraderbrain","title":"Wanderingtraderbrain","description":"Controls the AI behavior of the Wandering Trader, managing movement, face-targeting, stock exhaustion chattering, and route following.","permalink":"/dst-api-webdocs/docs/game-scripts/brains/wanderingtraderbrain"},{"id":"game-scripts/prefabs/woby_shadow_fx","title":"Woby Shadow Fx","description":"Creates transient visual effects for Woby\'s dash ability, including a moving\u8ffd\u968f trail and a static silhouette, managed via network-aware prefabs.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/woby_shadow_fx"},{"id":"game-scripts/brains/wormwood_fruitdragonbrain","title":"Wormwood Fruitdragonbrain","description":"AI brain component for the Wormwood Fruit Dragon entity that manages its movement and combat behavior using a behavior tree.","permalink":"/dst-api-webdocs/docs/game-scripts/brains/wormwood_fruitdragonbrain"},{"id":"game-scripts/brains/wormwood_lightflierbrain","title":"Wormwood Lightflierbrain","description":"Controls the behavior tree logic for the Wormwood Lightflier entity, primarily managing panic responses and walk speed adjustments via the locomotor component.","permalink":"/dst-api-webdocs/docs/game-scripts/brains/wormwood_lightflierbrain"}],"unlisted":false}}')}}]);